import{_ as r,o,c as a,a0 as n}from"./chunks/framework.DV6pVIgV.js";const c=JSON.parse('{"title":"監控、合規與治理","description":"","frontmatter":{},"headers":[],"relativePath":"clf-c02/14.md","filePath":"clf-c02/14.md","lastUpdated":1783683776000}'),d={name:"clf-c02/14.md"};function s(l,t,e,i,g,h){return o(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="監控、合規與治理" tabindex="-1">監控、合規與治理 <a class="header-anchor" href="#監控、合規與治理" aria-label="Permalink to &quot;監控、合規與治理&quot;">​</a></h1><p>CloudWatch、CloudTrail、Config、Health 與 Trusted Advisor。</p><h2 id="先備知識" tabindex="-1">先備知識 <a class="header-anchor" href="#先備知識" aria-label="Permalink to &quot;先備知識&quot;">​</a></h2><ul><li><p><strong>監控與可觀測性（Monitoring / Observability）</strong></p><ul><li><a href="https://aws.amazon.com/cloudops/monitoring-and-observability/" target="_blank" rel="noreferrer">監控與可觀測性（AWS）</a></li></ul></li><li><p><strong>合規與稽核（Compliance / Audit）</strong></p><ul><li><a href="https://aws.amazon.com/tw/compliance/" target="_blank" rel="noreferrer">AWS 合規計畫（AWS）</a></li></ul></li></ul><h2 id="為什麼要監控" tabindex="-1">為什麼要監控 <a class="header-anchor" href="#為什麼要監控" aria-label="Permalink to &quot;為什麼要監控&quot;">​</a></h2><p>把服務丟上雲不是結束。你需要持續知道：資源跑得好不好？有沒有人動了不該動的東西？設定有沒有偏離規範？沒有監控，問題往往是「出事了才發現」，而且查不出是誰、什麼時候、改了什麼。</p><h2 id="amazon-cloudwatch-效能與運作監控" tabindex="-1">Amazon CloudWatch（效能與運作監控） <a class="header-anchor" href="#amazon-cloudwatch-效能與運作監控" aria-label="Permalink to &quot;Amazon CloudWatch（效能與運作監控）&quot;">​</a></h2><p>CloudWatch 回答的問題是：「我的資源現在表現如何？」它持續收集各種<strong>指標（metrics）</strong>（CPU 使用率、網路流量、請求數…），讓你設<strong>警報</strong>、看<strong>儀表板</strong>、集中<strong>日誌</strong>。</p><p>把它想成系統的<strong>健康監測儀</strong>——隨時顯示心跳、血壓（= CPU、流量等指標），數值異常就觸發警報叫人來。</p><table tabindex="0"><thead><tr><th>功能</th><th>做什麼</th></tr></thead><tbody><tr><td><strong>Metrics（指標）</strong></td><td>收集資源的效能數據（如 EC2 的 CPU 使用率）</td></tr><tr><td><strong>Alarms（警報）</strong></td><td>指標超過門檻就動作，如「CPU &gt; 80% → 發通知 / 觸發 Auto Scaling」</td></tr><tr><td><strong>Dashboards（儀表板）</strong></td><td>把指標視覺化成圖表，一眼看懂系統狀態</td></tr><tr><td><strong>Logs（日誌）</strong></td><td>集中收集應用程式與服務的日誌，方便查詢</td></tr></tbody></table><blockquote><p>📌 <strong>解題方向</strong>：「監控效能 / 設定門檻警報 / 視覺化指標」→ <strong>CloudWatch</strong>。CloudWatch Alarm 也常和 Auto Scaling、SNS 通知搭配。</p></blockquote><h2 id="aws-cloudtrail-活動稽核" tabindex="-1">AWS CloudTrail（活動稽核） <a class="header-anchor" href="#aws-cloudtrail-活動稽核" aria-label="Permalink to &quot;AWS CloudTrail（活動稽核）&quot;">​</a></h2><p>CloudTrail 回答的問題是：「是誰、在什麼時候、從哪裡、做了什麼動作？」它記錄帳號裡的<strong>每一個 API 呼叫</strong>——因為 AWS 上所有操作（主控台點選、CLI、SDK）本質都是 API 呼叫，所以等於記錄了所有活動。</p><p>把它想成大樓的<strong>監視器錄影 + 門禁日誌</strong>：誰幾點刷卡進來、開了哪扇門、做了什麼，全都留底。</p><ul><li><strong>記錄內容</strong>：誰（哪個身分）、做了什麼動作（哪個 API）、什麼時間、來源 IP</li><li><strong>典型用途</strong>：資安鑑識（「是誰刪了那個 S3 Bucket？」）、稽核、合規追溯</li></ul><blockquote><p>📌 <strong>解題方向</strong>：「<strong>追查是誰做了某個操作 / 稽核帳號活動 / API 呼叫紀錄</strong>」→ <strong>CloudTrail</strong>。</p></blockquote><h2 id="aws-config-組態記錄與合規檢查" tabindex="-1">AWS Config（組態記錄與合規檢查） <a class="header-anchor" href="#aws-config-組態記錄與合規檢查" aria-label="Permalink to &quot;AWS Config（組態記錄與合規檢查）&quot;">​</a></h2><p>Config 回答的問題是：「我的資源設定長什麼樣？什麼時候被改過？符不符合規範？」它持續記錄資源的組態（configuration）與每次變更，還能用 <strong>Config Rules</strong> 自動檢查是否合規。</p><p>把它想成每個房間的<strong>設定快照與變更記錄簿</strong>：現在的擺設是什麼、上週長什麼樣、什麼時候被誰改成現在這樣、有沒有違反規定。</p><ul><li><strong>用途</strong>：組態變更追蹤（「這個安全群組上週的規則是什麼？」）、<strong>合規檢查</strong>（「我所有的 EBS 磁碟區都加密了嗎？」「有沒有 S3 Bucket 被設成公開？」）</li></ul><table tabindex="0"><thead><tr><th></th><th>CloudWatch</th><th>CloudTrail</th><th>Config</th></tr></thead><tbody><tr><td>回答的問題</td><td>資源表現如何？</td><td>誰做了什麼動作？</td><td>設定是什麼 / 變了沒 / 合規嗎？</td></tr><tr><td>監看對象</td><td>效能指標、日誌</td><td>API 呼叫 / 帳號活動</td><td>資源組態與變更</td></tr><tr><td>類比</td><td>健康監測儀</td><td>監視器 / 門禁日誌</td><td>設定快照與變更記錄簿</td></tr><tr><td>典型用途</td><td>警報、儀表板、效能監控</td><td>稽核、追查誰改了東西</td><td>合規檢查、組態變更追蹤</td></tr></tbody></table><blockquote><p><strong>效能看 CloudWatch、動作看 CloudTrail、組態與合規看 Config。</strong></p></blockquote><h2 id="其他合規資源" tabindex="-1">其他合規資源 <a class="header-anchor" href="#其他合規資源" aria-label="Permalink to &quot;其他合規資源&quot;">​</a></h2><ul><li><strong>AWS Artifact</strong>：下載 AWS 的合規報告（SOC、PCI DSS、ISO…）</li><li><strong>AWS Audit Manager</strong>：自動蒐集證據、協助跑稽核流程</li></ul><h2 id="aws-organizations-多帳號治理" tabindex="-1">AWS Organizations（多帳號治理） <a class="header-anchor" href="#aws-organizations-多帳號治理" aria-label="Permalink to &quot;AWS Organizations（多帳號治理）&quot;">​</a></h2><p>當你有很多 AWS 帳號（不同團隊、不同專案），需要<strong>集中治理</strong>。AWS Organizations 讓你把多個帳號統一管理：</p><table tabindex="0"><thead><tr><th>功能</th><th>做什麼</th></tr></thead><tbody><tr><td><strong>集中管理 / OU</strong></td><td>把帳號分組成組織單位（OU），統一套政策</td></tr><tr><td><strong>SCP（服務控制政策）</strong></td><td>設帳號的<strong>權限上限</strong>（如「這些帳號只能用特定 Region」）</td></tr><tr><td><strong>合併帳單（Consolidated Billing）</strong></td><td>多帳號<strong>一張帳單</strong>，並可<strong>合併用量享量大折扣</strong></td></tr></tbody></table><blockquote><p>📌 <strong>SCP</strong> 設的是上限 / 邊界，不是授權（最終權限 = IAM ∩ SCP）。</p></blockquote><h2 id="aws-trusted-advisor-最佳實踐健檢" tabindex="-1">AWS Trusted Advisor（最佳實踐健檢） <a class="header-anchor" href="#aws-trusted-advisor-最佳實踐健檢" aria-label="Permalink to &quot;AWS Trusted Advisor（最佳實踐健檢）&quot;">​</a></h2><p>Trusted Advisor 像一位<strong>自動的最佳實踐稽核員</strong>：掃描你的帳號，對照 AWS 最佳實踐，給出改善建議（紅 = 建議行動、黃 = 建議調查、綠 = 沒問題）。</p><p>它的檢查分成<strong>六大類</strong>：</p><table tabindex="0"><thead><tr><th>類別</th><th>檢查什麼</th></tr></thead><tbody><tr><td><strong>成本最佳化</strong></td><td>找出浪費的閒置資源（沒用的 EIP、低使用率 EC2）</td></tr><tr><td><strong>效能</strong></td><td>找出可提升效能的設定</td></tr><tr><td><strong>安全</strong></td><td>對照安全最佳實踐（如 root 帳號有沒有開 MFA、S3 權限）</td></tr><tr><td><strong>容錯（Fault Tolerance）</strong></td><td>找單點故障（如 RDS 沒開 Multi-AZ、ASG 只在單一 AZ）</td></tr><tr><td><strong>服務限額（Service Limits）</strong></td><td>用量接近帳號配額時提醒你</td></tr><tr><td><strong>卓越營運（Operational Excellence）</strong></td><td>營運管理 hygiene（如是否用 Config 規則、Lambda runtime 是否過時）</td></tr></tbody></table><p><strong>三個「檢查」服務辨別</strong>：</p><ul><li><strong>Trusted Advisor</strong> = 對照 <strong>AWS 最佳實踐</strong>（涵蓋成本 / 效能 / 安全 / 容錯 / 限額 / 營運）</li><li><strong>Inspector</strong> = 找軟體漏洞</li><li><strong>Config</strong> = 檢查資源組態是否合規</li></ul><h2 id="重點整理" tabindex="-1">重點整理 <a class="header-anchor" href="#重點整理" aria-label="Permalink to &quot;重點整理&quot;">​</a></h2><ul><li><strong>CloudWatch</strong>（效能指標 / 警報 / 儀表板）、<strong>CloudTrail</strong>（誰做了什麼——API 活動稽核）、<strong>Config</strong>（設定是什麼 / 變了沒 / 合規嗎）。</li><li><strong>CloudWatch</strong> Alarm 常搭 Auto Scaling / SNS；<strong>CloudTrail</strong> 用於資安鑑識與稽核；<strong>Config</strong> 搭配 Config Rules 自動合規檢查</li><li><strong>AWS Organizations</strong>：集中治理多帳號、<strong>SCP</strong>（權限上限）、<strong>合併帳單</strong>（量大折扣）</li><li><strong>Trusted Advisor</strong>：最佳實踐健檢</li></ul><table tabindex="0"><thead><tr><th>情境需求</th><th>答案</th></tr></thead><tbody><tr><td>監控 EC2 的 CPU、設門檻警報</td><td><strong>CloudWatch</strong></td></tr><tr><td>把效能指標做成儀表板</td><td><strong>CloudWatch Dashboards</strong></td></tr><tr><td>追查「是誰刪了那個 Bucket」</td><td><strong>CloudTrail</strong></td></tr><tr><td>稽核帳號的所有 API 活動</td><td><strong>CloudTrail</strong></td></tr><tr><td>檢查「所有 EBS 是否都加密」、追蹤組態變更</td><td><strong>AWS Config</strong></td></tr><tr><td>下載 PCI DSS / SOC 合規報告</td><td><strong>AWS Artifact</strong></td></tr><tr><td>多帳號集中治理、設權限上限</td><td><strong>AWS Organizations（SCP）</strong></td></tr><tr><td>多帳號合併帳單、享量大折扣</td><td><strong>Consolidated Billing</strong> （Organizations）</td></tr><tr><td>對照最佳實踐做帳號健檢（含成本 / 安全）</td><td><strong>Trusted Advisor</strong></td></tr></tbody></table><h2 id="延伸閱讀" tabindex="-1">延伸閱讀 <a class="header-anchor" href="#延伸閱讀" aria-label="Permalink to &quot;延伸閱讀&quot;">​</a></h2><ul><li><a href="https://sre.google/books/" target="_blank" rel="noreferrer">Google SRE Book</a></li></ul>',39)])])}const b=r(d,[["render",s]]);export{c as __pageData,b as default};
